'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { DashboardHeader } from '@/components/dashboard/header'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Switch } from '@/components/ui/switch'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Loader2, ArrowLeft } from 'lucide-react'
import Link from 'next/link'

const productSchema = z.object({
  name: z.string().min(2, 'Le nom doit contenir au moins 2 caracteres'),
  sku: z.string().min(1, 'Le SKU est requis'),
  description: z.string().optional(),
  category: z.string().optional(),
  baseUnit: z.string().min(1, 'L\'unite de base est requise'),
  purchasePrice: z.number().min(0, 'Le prix d\'achat doit etre positif'),
  sellingPrice: z.number().min(0, 'Le prix de vente doit etre positif'),
  isActive: z.boolean().default(true),
})

type ProductForm = z.infer<typeof productSchema>

const categories = [
  'Boissons gazeuses',
  'Bieres',
  'Jus de fruits',
  'Eaux minerales',
  'Vins et spiritueux',
  'Autres',
]

const units = [
  { value: 'bouteille', label: 'Bouteille' },
  { value: 'canette', label: 'Canette' },
  { value: 'pack', label: 'Pack' },
  { value: 'casier', label: 'Casier' },
  { value: 'carton', label: 'Carton' },
  { value: 'litre', label: 'Litre' },
]

export default function NewProductPage() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const {
    register,
    handleSubmit,
    setValue,
    watch,
    formState: { errors },
  } = useForm<ProductForm>({
    resolver: zodResolver(productSchema),
    defaultValues: {
      isActive: true,
      purchasePrice: 0,
      sellingPrice: 0,
    },
  })

  const isActive = watch('isActive')

  async function onSubmit(data: ProductForm) {
    setIsLoading(true)
    setError(null)

    try {
      const response = await fetch('/api/products', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })

      const result = await response.json()

      if (!response.ok) {
        setError(result.error || 'Une erreur est survenue')
        return
      }

      router.push('/dashboard/products')
      router.refresh()
    } catch {
      setError('Une erreur est survenue. Veuillez reessayer.')
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="flex flex-col min-h-screen">
      <DashboardHeader
        title="Nouveau produit"
        description="Ajoutez un nouveau produit a votre catalogue"
      />

      <main className="flex-1 p-4 lg:p-6">
        <div className="mb-6">
          <Button variant="ghost" size="sm" asChild>
            <Link href="/dashboard/products">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Retour aux produits
            </Link>
          </Button>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="max-w-2xl space-y-6">
          {error && (
            <div className="rounded-lg bg-destructive/10 border border-destructive/20 p-4 text-sm text-destructive">
              {error}
            </div>
          )}

          <Card>
            <CardHeader>
              <CardTitle>Informations generales</CardTitle>
              <CardDescription>
                Les informations de base du produit
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="name">Nom du produit *</Label>
                  <Input
                    id="name"
                    placeholder="Ex: Coca-Cola 33cl"
                    {...register('name')}
                    disabled={isLoading}
                  />
                  {errors.name && (
                    <p className="text-sm text-destructive">{errors.name.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="sku">SKU / Reference *</Label>
                  <Input
                    id="sku"
                    placeholder="Ex: COCA-33CL"
                    {...register('sku')}
                    disabled={isLoading}
                  />
                  {errors.sku && (
                    <p className="text-sm text-destructive">{errors.sku.message}</p>
                  )}
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="description">Description</Label>
                <Textarea
                  id="description"
                  placeholder="Description du produit (optionnel)"
                  {...register('description')}
                  disabled={isLoading}
                />
              </div>

              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="category">Categorie</Label>
                  <Select
                    onValueChange={(value) => setValue('category', value)}
                    disabled={isLoading}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selectionner une categorie" />
                    </SelectTrigger>
                    <SelectContent>
                      {categories.map((cat) => (
                        <SelectItem key={cat} value={cat}>
                          {cat}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="baseUnit">Unite de base *</Label>
                  <Select
                    onValueChange={(value) => setValue('baseUnit', value)}
                    disabled={isLoading}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selectionner une unite" />
                    </SelectTrigger>
                    <SelectContent>
                      {units.map((unit) => (
                        <SelectItem key={unit.value} value={unit.value}>
                          {unit.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {errors.baseUnit && (
                    <p className="text-sm text-destructive">{errors.baseUnit.message}</p>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Prix</CardTitle>
              <CardDescription>
                Definissez les prix d&apos;achat et de vente
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="purchasePrice">Prix d&apos;achat (FCFA) *</Label>
                  <Input
                    id="purchasePrice"
                    type="number"
                    min="0"
                    placeholder="0"
                    {...register('purchasePrice', { valueAsNumber: true })}
                    disabled={isLoading}
                  />
                  {errors.purchasePrice && (
                    <p className="text-sm text-destructive">{errors.purchasePrice.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="sellingPrice">Prix de vente (FCFA) *</Label>
                  <Input
                    id="sellingPrice"
                    type="number"
                    min="0"
                    placeholder="0"
                    {...register('sellingPrice', { valueAsNumber: true })}
                    disabled={isLoading}
                  />
                  {errors.sellingPrice && (
                    <p className="text-sm text-destructive">{errors.sellingPrice.message}</p>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Statut</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="isActive">Produit actif</Label>
                  <p className="text-sm text-muted-foreground">
                    Les produits inactifs ne seront pas disponibles a la vente
                  </p>
                </div>
                <Switch
                  id="isActive"
                  checked={isActive}
                  onCheckedChange={(checked) => setValue('isActive', checked)}
                  disabled={isLoading}
                />
              </div>
            </CardContent>
          </Card>

          <div className="flex justify-end gap-4">
            <Button type="button" variant="outline" asChild disabled={isLoading}>
              <Link href="/dashboard/products">Annuler</Link>
            </Button>
            <Button type="submit" disabled={isLoading}>
              {isLoading ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Creation...
                </>
              ) : (
                'Creer le produit'
              )}
            </Button>
          </div>
        </form>
      </main>
    </div>
  )
}
